import{_ as i,o as s,c as e,a5 as l}from"./chunks/framework.B5tqjWbr.js";const k=JSON.parse('{"title":"概念：单相 PFC 电压环如何生成电流幅值","description":"","frontmatter":{"date":"2026-06-21T00:00:00.000Z","category":"电源控制","source":"power","visibility":"public","title":"概念：单相 PFC 电压环如何生成电流幅值","tags":["power-electronics"],"status":"learning","summary":"功率因数校正（power factor correction / PFC）的电压环（voltage loop）是一个慢环。它根据直流母线电压误差，输出电流参考的幅值命令。"},"headers":[],"relativePath":"content/power/concepts/power-electronics/single-phase-pfc-voltage-loop.md","filePath":"content/power/concepts/power-electronics/single-phase-pfc-voltage-loop.md","lastUpdated":null}'),t={name:"content/power/concepts/power-electronics/single-phase-pfc-voltage-loop.md"};function p(n,a,o,h,r,c){return s(),e("div",null,[...a[0]||(a[0]=[l(`<h1 id="概念-单相-pfc-电压环如何生成电流幅值" tabindex="-1">概念：单相 PFC 电压环如何生成电流幅值 <a class="header-anchor" href="#概念-单相-pfc-电压环如何生成电流幅值" aria-label="Permalink to &quot;概念：单相 PFC 电压环如何生成电流幅值&quot;">​</a></h1><h2 id="_1-它是什么" tabindex="-1">1. 它是什么 <a class="header-anchor" href="#_1-它是什么" aria-label="Permalink to &quot;1. 它是什么&quot;">​</a></h2><p>功率因数校正（power factor correction / PFC）的电压环（voltage loop）是一个慢环。它根据直流母线电压误差，输出电流参考的幅值命令。</p><p>本节用电导命令（conductance command / G）表示这个幅值：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>i_ref(t) = G * v_ac(t)</span></span></code></pre></div><p>上一节解释了 <code>i_ref</code> 的形状；本节解释 <code>G</code> 怎么随母线电压变化。本节不包含公司内部代码、未公开产品方案、客户项目参数或内部测试数据。维护本学习仓库时，不能记录公司内部代码、未公开产品方案、客户项目参数、内部测试数据。</p><h2 id="_2-ups-为什么需要它" tabindex="-1">2. UPS 为什么需要它 <a class="header-anchor" href="#_2-ups-为什么需要它" aria-label="Permalink to &quot;2. UPS 为什么需要它&quot;">​</a></h2><p>不间断电源（uninterruptible power supply / UPS）的 PFC 前级要维持直流母线电压。如果负载功率突然增加，母线电容会放电，母线电压下降。电压环必须提高输入功率，让母线回到目标值。</p><p>如果没有电压环：</p><ul><li>负载变大时母线会持续下降。</li><li>负载变小时母线可能过压。</li><li>后级逆变器的输入条件会变差。</li></ul><h2 id="_3-物理直觉" tabindex="-1">3. 物理直觉 <a class="header-anchor" href="#_3-物理直觉" aria-label="Permalink to &quot;3. 物理直觉&quot;">​</a></h2><p>直流母线电容像水箱。负载是出水，PFC 输入功率是进水。水位低于目标时，电压环开大进水阀门；水位高于目标时，电压环关小阀门。</p><p>这里的“阀门开度”就是电流参考幅值，本文用电导 <code>G</code> 表示。</p><h2 id="_4-数学形式" tabindex="-1">4. 数学形式 <a class="header-anchor" href="#_4-数学形式" aria-label="Permalink to &quot;4. 数学形式&quot;">​</a></h2><p>电压误差：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>e_v[k] = Vbus_ref - Vbus[k]</span></span></code></pre></div><p>比例积分控制器（proportional-integral controller / PI）：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>G[k] = clamp(Kp * e_v[k] + integral[k], Gmin, Gmax)</span></span>
<span class="line"><span>integral[k+1] = integral[k] + Ki * e_v[k] * Ts</span></span></code></pre></div><p>输入功率近似：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Pin[k] = G[k] * Vrms^2</span></span></code></pre></div><p>母线能量平衡：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>0.5 * Cbus * (Vbus[k+1]^2 - Vbus[k]^2) = (Pin[k] - Pload[k]) * Ts</span></span></code></pre></div><h2 id="_5-一个仿真任务与仿真观察" tabindex="-1">5. 一个仿真任务与仿真观察 <a class="header-anchor" href="#_5-一个仿真任务与仿真观察" aria-label="Permalink to &quot;5. 一个仿真任务与仿真观察&quot;">​</a></h2><p>运行：</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">python simulations\\python\\single_phase_pfc_voltage_loop.py</span></span></code></pre></div><p>对比一个仿真任务：</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">python simulations\\python\\single_phase_pfc_voltage_loop.py </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">load</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">power</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">step </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">900</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> --</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">output simulations\\results\\pfc_voltage_loop_900w.png </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">no</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">open</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">python simulations\\python\\single_phase_pfc_voltage_loop.py </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">load</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">power</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">step </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1500</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> --</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">output simulations\\results\\pfc_voltage_loop_1500w.png </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">no</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">open</span></span></code></pre></div><p>观察：</p><ul><li>负载从 600 W 阶跃到 1200 W 后，母线电压先下降。</li><li>电压环提高 <code>G</code>。</li><li>输入功率 <code>Pin</code> 上升。</li><li>电流参考的均方根值（root mean square / RMS）随 <code>G</code> 增大。</li><li>母线电压逐步回到参考值附近。</li></ul><h2 id="_6-固件落地" tabindex="-1">6. 固件落地 <a class="header-anchor" href="#_6-固件落地" aria-label="Permalink to &quot;6. 固件落地&quot;">​</a></h2><p>真实 PFC 固件中，电压环通常运行得比电流环慢。它输出的可能不是 <code>G</code>，而是：</p><ul><li>电流幅值命令。</li><li>功率命令。</li><li>电导命令。</li><li>归一化电流参考幅值。</li></ul><p>工程阅读时先找：母线电压采样在哪里进入 PI，PI 输出如何限幅，输出又在哪里乘以输入电压或单位正弦。</p><h2 id="_7-常见误解" tabindex="-1">7. 常见误解 <a class="header-anchor" href="#_7-常见误解" aria-label="Permalink to &quot;7. 常见误解&quot;">​</a></h2><ul><li><p>错误理解：PFC 电压环直接控制 PWM。<br> 正确理解：电压环通常只给电流幅值，内层电流环才负责快速跟踪。</p></li><li><p>错误理解：电压环越快越好。<br> 正确理解：单相 PFC 母线有二倍工频纹波，电压环太快会把纹波错误调进电流参考。</p></li><li><p>错误理解：负载阶跃后母线不能有任何下跌。<br> 正确理解：母线电容承担能量缓冲，短暂下跌正常，关键是恢复过程和保护边界。</p></li></ul><h2 id="_8-验收标准" tabindex="-1">8. 验收标准 <a class="header-anchor" href="#_8-验收标准" aria-label="Permalink to &quot;8. 验收标准&quot;">​</a></h2><ul><li>能解释电压环（voltage loop）为什么是慢速外环。</li><li>能解释 <code>G</code> 增大为什么会提高输入功率。</li><li>能在 <code>single_phase_pfc_voltage_loop.py</code> 生成的图中指出母线电压、电导命令、输入功率、负载功率和电流参考 RMS。</li><li>能解释为什么需要 <code>Gmax</code> 限幅和抗积分饱和。</li><li>能基于仿真图准备具体导师问题。</li></ul><h2 id="_9-复盘问题" tabindex="-1">9. 复盘问题 <a class="header-anchor" href="#_9-复盘问题" aria-label="Permalink to &quot;9. 复盘问题&quot;">​</a></h2><ul><li>默认仿真中负载从多少 W 阶跃到多少 W？发生在多少 ms？</li><li>负载阶跃后，为什么 <code>G</code> 和电流参考 RMS 会升高？</li><li>如果电压环追踪二倍工频纹波，会对输入电流参考造成什么影响？</li></ul><h2 id="_10-导师问题" tabindex="-1">10. 导师问题 <a class="header-anchor" href="#_10-导师问题" aria-label="Permalink to &quot;10. 导师问题&quot;">​</a></h2><ul><li>我用 <code>single_phase_pfc_voltage_loop.py</code> 看到负载从 600 W 到 1200 W 后，电压环提高 <code>G</code>，输入功率上升。公司 PFC 代码里电压环输出的是电流幅值、功率命令还是电导命令？</li><li>图中 <code>Gmax</code> 会限制最大输入功率。真实工程中 PFC 电压环输出限幅通常由哪些因素决定？</li><li>单相 PFC 母线上有二倍工频纹波。公司工程里电压环带宽如何避免追踪二倍频纹波？</li></ul>`,41)])])}const g=i(t,[["render",p]]);export{k as __pageData,g as default};
